css:
.req-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.req-table th,
.req-table td {
  padding: 8px;
}

.req-skills-list {
  margin: 0;
  padding-left: 18px;
}

.req-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
}

.req-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.req-table td:last-child,
.req-table th:last-child {
  border-right: none;
}

.req-table tbody tr:last-child td {
  border-bottom: none;
}

.req-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.print-heading {
  text-align: center;
  margin-bottom: 24px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.print-heading p {
  margin: 4px 0 0;
}

.section-heading {
  border-bottom: 1px solid #b40000;
  padding-bottom: 5px;
  margin-top: 20px;
  margin-bottom: 10px;
  font-size: 12pt;
  font-weight: 700;
  page-break-after: avoid;
}

@page {
  margin: 20mm 15mm 25mm 15mm;
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
